// Compute resume time: tomorrow at 9am CT (UTC-5 CST / UTC-6 CDT)
const now = new Date();
const tomorrow = new Date(now);
tomorrow.setDate(tomorrow.getDate() + 1);
tomorrow.setUTCHours(15, 0, 0, 0);

const body = $input.first().json.body;

// Required field validation
const required = ['attendee_name', 'phone', 'agent_name', 'agent_email', 'agent_phone', 'property_address'];
for (const field of required) {
  if (!body[field] || !String(body[field]).trim()) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Length caps — prevent oversized payloads to Claude
const maxLengths = { attendee_name: 100, brought_you_in: 500, property_notes: 1000 };
for (const [field, max] of Object.entries(maxLengths)) {
  if (body[field] && String(body[field]).length > max) {
    throw new Error(`Field too long: ${field} (max ${max} chars)`);
  }
}

return [{
  json: {
    resume_at:        tomorrow.toISOString(),
    attendee_name:    body.attendee_name    || '',
    phone:            body.phone            || '',
    email:            body.email            || '',
    brought_you_in:   body.brought_you_in   || '',
    property_address: body.property_address || '',
    property_notes:   body.property_notes   || '',
    agent_name:       body.agent_name       || '',
    agent_email:      body.agent_email      || '',
    agent_phone:      body.agent_phone      || '',
  }
}];

let insight_block = '';
let research_detail = '';
try {
  const research = $('Call Research Agent').first().json;
  if (research && research.status === 'ok') {
    insight_block = research.insight_block || '';
    const lines = [];
    if (research.walkability && research.walkability.description) {
      lines.push(`Walkability: ${research.walkability.description}`);
    }
    if (Array.isArray(research.schools) && research.schools.length > 0) {
      lines.push('Nearby schools:');
      research.schools.forEach(s => {
        let entry = `  - ${s.name} (${s.grades})`;
        if (s.rating) entry += ` — ${s.rating}/10`;
        if (s.distance_miles) entry += `, ${s.distance_miles} mi away`;
        lines.push(entry);
      });
    }
    if (research.market) {
      const m = research.market;
      const mParts = [];
      if (m.median_sale_price) mParts.push(`median sale price $${Number(m.median_sale_price).toLocaleString()}`);
      if (m.median_days_on_market) mParts.push(`avg ${m.median_days_on_market} days on market`);
      if (m.yoy_price_trend) mParts.push(`${m.yoy_price_trend} YoY`);
      if (mParts.length) lines.push(`Market: ${mParts.join(' · ')}`);
    }
    research_detail = lines.join('\n');
  }
} catch(e) {}

return [{ json: { ...$('Prep Wait Time').first().json, insight_block, research_detail } }];

const response = $input.first().json;
const message = response.content[0].text.trim();

// Pull through all fields from the wait node output
const prev = $('Wait Until 9am CT').first().json;

const message_html = '<div style="font-family: Arial, sans-serif; font-size: 15px; line-height: 1.6; color: #222;">' +
  message.replace(/\n/g, '<br>') +
  '</div>';

return [{
  json: {
    message,
    message_html,
    attendee_name:    prev.attendee_name,
    phone:            prev.phone,
    email:            prev.email,
    property_address: prev.property_address,
    property_notes:   prev.property_notes,
    agent_name:       prev.agent_name,
    agent_email:      prev.agent_email,
    agent_phone:      prev.agent_phone,
    has_email:        (prev.email || '').trim().length > 0,
  }
}];
